code = """import json

# Load food-related papers (58 papers)
food_papers_path = locals().get('var_functions.query_db:8')
with open(food_papers_path, 'r') as f:
    food_papers = json.load(f)

food_titles = []
for paper in food_papers:
    filename = paper.get('filename', '')
    title = filename.replace('.txt', '') if filename else ''
    if title:
        food_titles.append(title)

print(f"Total food-related papers: {len(food_titles)}")
print("Sample titles:", food_titles[:5])

# Load all citations data
all_citations_path = locals().get('var_functions.query_db:24')
with open(all_citations_path, 'r') as f:
    all_citations = json.load(f)

print(f"Total papers with citations: {len(all_citations)}")

# Create a dictionary mapping titles to total citations
citations_dict = {item['title']: int(item['total_citations']) for item in all_citations}

# Find citations for food-related papers
food_citations = []
for title in food_titles:
    if title in citations_dict:
        food_citations.append({
            'title': title,
            'citations': citations_dict[title]
        })

print(f"Found citations for {len(food_citations)} food papers")

# Calculate total citations
total_citations = sum(item['citations'] for item in food_citations)

print(f"Total citation count for food papers: {total_citations}")

# Sort by citation count to see top papers
top_papers = sorted(food_citations, key=lambda x: x['citations'], reverse=True)[:10]

print("Top 10 food papers by citations:")
for paper in top_papers:
    print(f"  {paper['title']}: {paper['citations']} citations")

print('__RESULT__:')
print(json.dumps({
    'total_food_papers': len(food_citations),
    'total_citations': total_citations,
    'top_papers': top_papers
}))"""

